diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..2d6e92657e03 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1327,6 +1327,58 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
     return nullptr;

+  // Try to fold (X == C1) || ((X & Mask) == C2) into a single range.
+  // Also handle (X != C1) && ((X & Mask) != C2) via De Morgan.
+  if ((!IsAnd && Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ) ||
+      (IsAnd && Pred1 == ICmpInst::ICMP_NE && Pred2 == ICmpInst::ICMP_NE)) {
+    bool IsEq = Pred1 == ICmpInst::ICMP_EQ;
+    Value *X = nullptr;
+    const APInt *Mask = nullptr;
+    const APInt *C = nullptr;
+    const APInt *SingleC = nullptr;
+    Value *And = nullptr;
+    // Determine which side is masked.
+    if (match(V2, m_And(m_Specific(V1), m_APInt(Mask)))) {
+      And = V2;
+      X = V1;
+      C = C2;
+      SingleC = C1;
+    } else if (match(V1, m_And(m_Specific(V2), m_APInt(Mask)))) {
+      And = V1;
+      X = V2;
+      C = C1;
+      SingleC = C2;
+    }
+    if (X && Mask && C && SingleC && And && And->hasOneUse()) {
+      // Check that C is aligned with Mask.
+      if ((*C & *Mask) == *C) {
+        unsigned TrailingZeros = Mask->countTrailingZeros();
+        APInt Size = APInt(Mask->getBitWidth(), 1).shl(TrailingZeros);
+        // Mask must be ~(Size - 1), i.e., Mask == -Size.
+        if (*Mask == -Size) {
+          APInt Lower = *SingleC;
+          APInt Upper = *C + Size;
+          // Check adjacency: SingleC == C - 1 or SingleC == C + Size
+          if (Lower == *C - 1 || Upper == *SingleC) {
+            // Union is contiguous from min(Lower, *C) to max(Upper, *C + Size - 1)
+            APInt UnionLower = Lower.ult(*C) ? Lower : *C;
+            APInt UnionUpper = Upper.ugt(*C + Size) ? Upper : *C + Size;
+            // Ensure union size is (UnionUpper - UnionLower).
+            APInt Offset = UnionLower;
+            APInt RangeSize = UnionUpper - UnionLower;
+            Type *Ty = X->getType();
+            Value *NewV = Builder.CreateAdd(X, ConstantInt::get(Ty, -Offset));
+            Value *Cmp = Builder.CreateICmpULT(NewV, ConstantInt::get(Ty, RangeSize));
+            // For AND of NE, we need the complement (intersection of complements).
+            if (!IsEq)
+              Cmp = Builder.CreateNot(Cmp);
+            return Cmp;
+          }
+        }
+      }
+    }
+  }
+
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;

